COPY public.statements (id, name, alias, basics_description, basics_status, basics_statement, basics_issued_date, basics_authority_id, generate_slug, slug, updated_at, created_at) FROM stdin;
5	Press Release - AF Motorsport 2026 Season Announcement	press-release-2026-season	Official press release announcing AF Motorsport's 2026 competitive program including series participation, driver lineup, technical partnerships, and season objectives. Distributed to motorsport media, partners, and stakeholders.	Published	{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "AF Motorsport Announces Expanded 2026 Program with Multi-Series Campaign", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "ESTORIL, PORTUGAL — AF Motorsport today announced its most ambitious competitive program to date, confirming participation in multiple championships for the 2026 season alongside an expanded driver lineup and new technical partnerships.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "The Estoril-based organization will field entries in the Porsche Sprint Challenge Ibérica, with additional programs to be announced in the coming weeks. Team Principal André Fernandes has assembled a strengthened technical department and invested in enhanced operational capabilities to support the expanded program.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "André Fernandes returns to lead the team's Porsche campaign, building on a successful 2025 season that included multiple podium finishes. Additional driver announcements for companion entries and support categories will follow as contracts are finalized.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}], "direction": null}}	2026-01-10 17:00:00+05:30	4	f	press-release---af-motorsport-2026-season-announcement	2026-04-10 10:15:26.331+05:30	2026-04-09 18:57:58.138+05:30
3	AF Motorsport Mission Statement	mission-statement	Core mission declaration that defines AF Motorsport's fundamental purpose, operational philosophy, and strategic direction. This statement articulates why the organization exists and what it fundamentally seeks to achieve through its competitive and commercial activities.	Published	{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Our Mission", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}], "direction": null}}	2020-01-15 17:00:00+05:30	4	f	af-motorsport-mission-statement	2026-04-10 10:15:48.903+05:30	2026-04-09 18:57:12.479+05:30
2	Racing Philosophy - AF Motorsport Approach	racing-philosophy	Foundational document articulating AF Motorsport's core beliefs about competitive racing, driver development, and team culture. This philosophy guides decision-making at all levels of the organization from strategic planning to trackside execution.	Published	{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "The AF Motorsport Racing Philosophy", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Preparation Precedes Performance", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "We believe that race results are determined long before lights out. Victory is forged in the workshop through meticulous preparation, in engineering meetings through rigorous analysis, and in countless simulator hours before arriving at the circuit. We never confuse effort with effectiveness—every hour of preparation must translate to measurable competitive advantage.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Data Informs, Instinct Executes", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "We embrace analytical rigor without surrendering to paralysis by data. Telemetry, simulation, and performance metrics provide the foundation for informed decision-making, but racing ultimately demands human judgment. Our drivers must develop the instinct to execute when milliseconds matter, trusting preparation while remaining adaptable to dynamic competitive situations.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Respect the Sport, Challenge Convention", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "We maintain profound respect for motorsport tradition, safety protocols, and sporting regulations while continuously questioning established methods. Innovation within the rulebook separates champions from competitors. We encourage intellectual curiosity at every level, rewarding those who identify legitimate competitive advantages others have overlooked.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Team Above Individual", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "While drivers occupy the spotlight, championships are won by organizations. Every mechanic turning wrenches, every engineer analyzing data, and every team member fulfilling their role contributes equally to our collective success. We celebrate individual achievement as the natural outcome of team excellence, never the reverse.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Long-Term Relationships Over Short-Term Gains", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "We build for sustainable success rather than momentary advantage. This applies equally to driver development, commercial partnerships, and technical direction. We make decisions that strengthen our position over seasons, not merely sessions, recognizing that motorsport reputations are earned through consistent demonstration of values and capability.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}], "direction": null}}	2021-03-10 17:00:00+05:30	5	f	racing-philosophy---af-motorsport-approach	2026-04-10 10:16:03.056+05:30	2026-04-09 18:57:10.392+05:30
6	AF Motorsport Diversity and Inclusion Commitment	diversity-inclusion-commitment	Formal organizational commitment to fostering diversity, equity, and inclusion within AF Motorsport's operations, competitive programs, and broader motorsport engagement. This statement establishes principles and actionable commitments to expand access and opportunity.	Published	{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Our Commitment to Diversity and Inclusion", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "AF Motorsport recognizes that motorsport has historically presented barriers to participation for underrepresented groups. We commit to being part of the solution—actively working to create pathways, remove obstacles, and foster an environment where talent can flourish regardless of background, gender, ethnicity, or circumstance.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Our Principles", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "We believe that diverse perspectives strengthen our organization, enhance our problem-solving capabilities, and expand our relevance to broader audiences. We further believe that merit and potential exist across all communities, and that our role includes identifying and developing talent that might otherwise go unrecognized due to structural barriers.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Our Commitments", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "This commitment is not performative—it is operational. We will measure our progress, acknowledge our shortcomings, and continuously work toward a more inclusive motorsport ecosystem.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}], "direction": null}}	2022-06-01 17:00:00+05:30	2	f	af-motorsport-diversity-and-inclusion-commitment	2026-04-10 10:15:16.918+05:30	2026-04-09 18:58:03.049+05:30
4	Sustainability Statement - AF Motorsport Environmental Responsibility	sustainability-statement	Organizational position on environmental sustainability and commitment to reducing motorsport's ecological footprint. Outlines specific initiatives, targets, and accountability measures for environmental performance.	Published	{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Environmental Responsibility at AF Motorsport", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}, {"type": "linebreak", "version": 1}, {"mode": "normal", "text": "AF Motorsport acknowledges the environmental impact of motorsport activities and accepts responsibility to minimize our footprint while advocating for sustainable practices throughout the sport. We recognize that long-term viability of motorsport depends on environmental stewardship and adaptation to changing societal expectations.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}, {"type": "linebreak", "version": 1}, {"mode": "normal", "text": "Our Commitments", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}, {"type": "linebreak", "version": 1}, {"mode": "normal", "text": "2026 Targets", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}, {"type": "linebreak", "version": 1}, {"mode": "normal", "text": "We commit to transparency in reporting our environmental performance and to continuous improvement in our sustainability practices.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}], "direction": null}}	2025-01-20 17:00:00+05:30	5	f	sustainability-statement---af-motorsport-environmental-responsibility	2026-04-10 10:15:38.376+05:30	2026-04-09 18:57:34.594+05:30
1	AF Motorsport Vision Statement	vision-statement	Forward-looking vision statement describing AF Motorsport's aspirational future state and long-term organizational goals. This declaration provides strategic direction and inspiration for all team members, partners, and stakeholders.	Published	{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "AF Motorsport envisions becoming the Iberian Peninsula's premier independent motorsport organization—a benchmark for professionalism, driver development, and competitive achievement. Within five years, we aim to establish championship-winning programs across multiple categories, serve as the definitive pathway for Portuguese and Spanish driving talent, and build commercial partnerships that demonstrate the unique value proposition of motorsport investment.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Our vision extends to the broader motorsport ecosystem: we will contribute to the growth of Iberian motorsport through event promotion, youth engagement programs, and knowledge sharing that elevates the entire paddock. We see AF Motorsport as a career destination where the region's finest mechanics, engineers, and operational staff can develop their craft at the highest levels of the sport.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "We will measure our success not solely through silverware, but through the careers we launch, the partnerships we sustain, and the reputation we build as an organization of integrity, excellence, and unwavering commitment.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}], "direction": null}}	2020-01-15 17:00:00+05:30	7	f	af-motorsport-vision-statement	2026-04-10 10:16:13.6+05:30	2026-04-09 18:57:10.368+05:30
8	Murça 2025 Reflection	murca-2025-reflection	AF Motorsport reflects on the memorable 2025 Rampa Porca de Murça ahead of the 2026 edition, capturing the emotional connection between drivers and Portugal's most challenging hillclimb.	Published	{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "The road remembers what we did in 2025.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "    ", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "    Speed, limits and pure adrenaline. Every corner, every braking zone, every moment of commitment etched into the asphalt.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "    ", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "    Now… we go again.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "    ", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "nor