COPY public.teams (id, name, alias, basics_tagline, basics_description, details_history, details_country_id, details_start_date, details_end_date, details_website, assets_logo_id, assets_cover_id, generate_slug, slug, updated_at, created_at) FROM stdin;
5	Autosport Portugal Lda	autosport-portugal	Motorsport Equipment and Service Provider	Autosport Portugal is a leading Portuguese motorsport equipment supplier and service provider. The organization supplies AF Motorsport with consumables, safety equipment, workshop supplies, and specialized motorsport products essential for team operations.	{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Established in 1995, Autosport Portugal has grown to become Portugal's premier motorsport supplier, serving teams across national and international competition. The company's comprehensive inventory and established supply chains ensure reliable access to essential motorsport products.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "    ", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": " Autosport Portugal's relationship with AF Motorsport extends beyond product supply to include technical consultation and logistics support. The partnership ensures AF Motorsport maintains operational readiness with consistent access to quality equipment and consumables.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [], "direction": null, "textStyle": "", "textFormat": 0}], "direction": null}}	12	1995-09-10 17:00:00+05:30	2026-04-15 17:00:00+05:30	https://www.autosport.pt	\N	\N	f	autosport-portugal-lda	2026-04-10 17:23:31.663+05:30	2026-04-09 20:20:40.327+05:30
4	JLF Designs UK	jlf-designs	Helmet Art and Motorsport Livery Design	JLF Designs is a premium helmet painting and motorsport livery design studio based in the United Kingdom. The studio has created custom helmet designs for AF Motorsport drivers including André Fernandes's signature Portuguese Navigator concept, and provides livery design consultation for the team's competition vehicles.	{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": " Established by Jason Lefroy, JLF Designs has earned international recognition for exceptional helmet artwork and motorsport livery design. The studio's work adorns helmets of drivers across Formula 1, GT racing, and international Porsche championships, with a reputation for translating driver personalities and heritage into striking visual designs.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "    ", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "    JLF Designs has collaborated with AF Motorsport since the team's Porsche program inception, developing the distinctive helmet designs that have become synonymous with the team's visual identity. The partnership combines British design craftsmanship with Portuguese racing heritage.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}], "direction": null}}	27	2010-03-01 17:00:00+05:30	2026-10-22 17:00:00+05:30	https://www.jlfdesigns.com	\N	\N	f	jlf-designs-uk	2026-04-10 17:27:06.911+05:30	2026-04-09 20:19:37.671+05:30
7	Steiner Racing	steiner-racing	German Precision in GT Competition	Steiner Racing is a German motorsport organization competing in European GT and Porsche championships. The team fields Porsche 992 GT3 Cup machinery in the GT Winter Series, partnering with AF Motorsport for selected events.	{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Founded by former Porsche Cup competitor Markus Steiner, Team Steiner Racing has established itself within European Porsche competition through meticulous preparation and professional race execution. The team's collaboration with AF Motorsport at Barcelona demonstrated effective partnership, with the combined entry securing a Cup 2 class victory by a narrow 0.637-second margin.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "    ", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "    The organization's philosophy emphasizes driver development alongside competitive achievement, making them natural partners for AF Motorsport's approach. Shared technical resources and complementary expertise benefit both organizations.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}], "direction": null}}	57	2019-03-01 17:00:00+05:30	\N	https://www.steiner-racing.de	\N	\N	f	steiner-racing	2026-04-10 17:16:27.338+05:30	2026-04-10 15:49:07.575+05:30
2	Porsche Motorsport Ibérica	porsche-motorsport-iberica	Regional Porsche Motorsport Operations	The Iberian regional division of Porsche Motorsport, responsible for customer racing support, championship organization, and technical assistance for Porsche competition programs across Portugal and Spain. This entity manages the Porsche Sprint Challenge Ibérica championship and provides essential support to regional Porsche racing teams.	{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Porsche Motorsport Ibérica was established to provide dedicated support for the growing Porsche customer racing community in Portugal and Spain. The organization coordinates championship operations, technical support, parts supply, and driver development programs specific to the Iberian region.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "    ", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "    The division played a central role in the merger of Portuguese and Spanish national Porsche championships into the unified Porsche Sprint Challenge Ibérica series, creating a stronger competitive platform and more efficient operational structure for regional Porsche competition.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}], "direction": null}}	42	2022-01-01 17:00:00+05:30	2026-04-29 17:00:00+05:30	https://www.porsche.com/spain/motorsport	\N	\N	f	porsche-motorsport-ibrica	2026-04-10 17:34:29.345+05:30	2026-04-09 20:15:33.024+05:30
6	Estoril Racing Experience	estoril-racing-experience	Track Day and Experience Organizer	Estoril Racing Experience organizes track days, driving experiences, and corporate motorsport events at Autódromo do Estoril and circuits throughout Portugal. The organization partners with AF Motorsport for guest driver programs and corporate partner activation events.	{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Estoril Racing Experience was founded to provide accessible motorsport experiences for enthusiasts and corporate clients. The organization has developed comprehensive programs ranging from introductory track experiences to advanced driver development, utilizing the Estoril circuit's facilities and a fleet of professionally maintained vehicles.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "    ", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "The partnership with AF Motorsport enables elevated experience offerings including Porsche Cup car passenger rides, professional instruction from team drivers, and behind-the-scenes access to professional race team operations.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}], "direction": null}}	6	2015-04-01 17:00:00+05:30	2026-04-22 17:00:00+05:30	https://www.estorilracingexperience.pt	\N	\N	f	estoril-racing-experience	2026-04-10 17:20:26.053+05:30	2026-04-09 20:21:44.99+05:30
3	P21 Motorsport	p21-motorsport	Technical Partner and Porsche Specialist	P21 Motorsport is a specialized Porsche service and preparation facility based in Barcelona, Spain. The organization provides technical support, parts supply, and specialist services to Porsche racing teams throughout the Iberian region. P21 serves as a key technical partner to AF Motorsport for specialized Porsche Cup car preparation and support.	{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Founded by former Porsche Motorsport technicians, P21 Motorsport has established itself as the reference for independent Porsche racing support in Iberia. The organization's expertise spans multiple generations of Porsche Cup cars, with particular specialization in the 991.2 and 992 platforms campaigned by AF Motorsport.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "    ", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "P21 provides specialist services including gearbox rebuilding, damper servicing, and advanced diagnostics that complement AF Motorsport's in-house capabilities. The partnership enables AF Motorsport to maintain factory-specification standards while benefiting from P21's specialized equipment and deep Porsche technical knowledge.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}], "direction": null}}	22	2018-05-15 17:00:00+05:30	2026-04-15 17:00:00+05:30	https://www.p21motorsport.com	\N	\N	f	p21-motorsport	2026-04-10 17:31:07.767+05:30	2026-04-09 20:17:01.365+05:30
1	AF Motorsport	af-motorsport	Performance Through Preparation	AF Motorsport is a professional motorsport organization based at Autódromo do Estoril, Portugal. Founded by André Fernandes, the team competes in the Porsche Sprint Challenge Ibérica championship and selected international events, combining Portuguese racing heritage with modern motorsport methodology. The organization's philosophy emphasizes meticulous preparation, driver development, and commercial professionalism.	{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": " AF Motorsport was established in 2020 by André Fernandes, transitioning from individual competition to a structured team organization. The team initially competed in Portuguese national championships, building operational capability and competitive experience before expanding to international Porsche competition in 2025.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "    ", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "    The organization's development has been methodical and strategic, with each season building upon previous foundations. Key milestones include establishing the Estoril workshop facility in 2020, expanding to a two-car Porsche program in 2025, and achieving multiple race victories and championship podiums in the Porsche Sprint Challenge Ibérica series.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "    ", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "    AF Motorsport's approach integrates Portuguese racing passion with professional standards and commercial discipline. The team has cultivated strong relationships with technical partners, sponsors, and the broader motorsport community, establishing a reputation for professionalism and competitive integrity.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}], "direction": null}}	15	2020-03-01 17:00:00+05:30	2026-04-28 17:00:00+05:30	https://www.afmotorsport.com	\N	\N	f	af-motorsport	2026-04-10 17:35:11.78+05:30	2026-04-09 20:14:04.252+05:30
\.


