COPY public.trainings (id, name, alias, basics_description, basics_intensity, basics_format, details_start_date, details_end_date, generate_slug, slug, updated_at, created_at) FROM stdin;
3	Race Strategy and Decision Making	race-strategy-training	{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Specialized training focusing on race strategy formulation, real-time decision making, and competitive scenario management for motorsport competition. The program develops the analytical and decision-making skills required for effective race strategy execution in the Porsche Sprint Challenge Ibérica format.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Training utilizes simulation exercises and historical race scenario analysis to develop strategic thinking and pressure decision capabilities. Participants practice responding to dynamic race situations including safety car periods, weather changes, and competitive threats.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}], "direction": null}}	medium	simulated	2026-02-25 17:00:00+05:30	2026-02-26 17:00:00+05:30	f	race-strategy-and-decision-making	2026-04-10 17:00:21.844+05:30	2026-04-10 09:40:04.109+05:30
2	Data Analysis and Telemetry Interpretation	data-analysis-telemetry-training	{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "start", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Structured training program developing competency in motorsport data analysis and telemetry interpretation using the Cosworth data acquisition system fitted to AF Motorsport's Porsche 992 GT3 Cup cars. The training enables drivers and engineers to extract actionable performance insights from vehicle data.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}, {"type": "linebreak", "version": 1}, {"mode": "normal", "text": "    ", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}, {"type": "linebreak", "version": 1}, {"mode": "normal", "text": "    The curriculum covers fundamental data concepts through to advanced analysis techniques, with emphasis on practical application to AF Motorsport's specific performance optimization context. Participants learn to identify performance opportunities, validate setup changes, and communicate findings effectively.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}], "direction": null}}	medium	classroom	2026-02-05 17:00:00+05:30	2026-02-07 17:00:00+05:30	f	data-analysis-and-telemetry-interpretation	2026-04-10 17:01:03.858+05:30	2026-04-10 00:58:01.447+05:30
5	Media and Communication Skills	media-communication-training	{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Professional development training focusing on effective communication with media, partners, and stakeholders. The program develops the skills required for professional media engagement including interview technique, message discipline, and brand representation.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "    ", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "    Training utilizes practical exercises including mock interviews, press conference simulations, and presentation practice. Participants receive constructive feedback on communication style, content clarity, and professional presence.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}], "direction": null}}	medium	group	2026-02-18 17:00:00+05:30	2026-02-18 17:00:00+05:30	f	media-and-communication-skills	2026-04-10 16:59:47.109+05:30	2026-04-10 09:46:50.375+05:30
4	Physical Preparation for Motorsport Performance	physical-preparation-training	{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Comprehensive physical conditioning program designed specifically for the physiological demands of professional motorsport competition. The training develops the strength, endurance, and recovery capabilities essential for maintaining peak performance through race weekends and across championship seasons.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "    ", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "    The program addresses motorsport-specific requirements including neck strength for g-force management, cardiovascular endurance for heat stress tolerance, and fine motor control for precise vehicle inputs under fatigue. Individual assessment and personalized programming ensure training targets each driver's specific development needs.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}], "direction": null}}	high	individual	2026-01-05 17:00:00+05:30	2026-12-15 17:00:00+05:30	f	physical-preparation-for-motorsport-performance	2026-04-10 16:59:32.394+05:30	2026-04-10 09:46:02.498+05:30
1	Porsche 992 GT3 Cup Systems Familiarization	porsche-992-systems-familiarization	{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "start", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Comprehensive technical training module covering all vehicle systems of the Porsche 992 GT3 Cup car. The training provides mechanics and engineers with detailed understanding of system architecture, component function, maintenance requirements, and diagnostic procedures essential for professional race car preparation and track side support.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}, {"type": "linebreak", "version": 1}, {"mode": "normal", "text": "    ", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}, {"type": "linebreak", "version": 1}, {"mode": "normal", "text": "    The curriculum progresses from foundational system overview through to advanced diagnostic techniques, ensuring participants develop both theoretical understanding and practical competency. Hands-on exercises utilizing team equipment reinforce classroom learning with direct application to AF Motorsport's specific operational context.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": null, "textStyle": "", "textFormat": 0}], "direction": null}}	high	hands_on	2026-01-15 17:00:00+05:30	2026-01-17 17:00:00+05:30	f	porsche-992-gt3-cup-systems-familiarization	2026-04-10 17:01:33.036+05:30	2026-04-10 00:54:41.75+05:30
